const statsRaw = $input.first().json;
const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);

if (!Array.isArray(stats)) {
  return [{ json: { error: 'No time stats data' } }];
}

// Aggregate by day-of-week (API provides daily data, not hourly)
const dayMap = {};
const dayNames = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];

stats.forEach(s => {
  if (!s.date) return;
  const date = new Date(s.date);
  const dayOfWeek = dayNames[date.getDay()];

  if (!dayMap[dayOfWeek]) {
    dayMap[dayOfWeek] = { clicks: 0, shows: 0, money: 0, revenue: 0, count: 0 };
  }

  dayMap[dayOfWeek].clicks += Number(s.clicks_count) || 0;
  dayMap[dayOfWeek].shows += Number(s.shows_count) || 0;
  dayMap[dayOfWeek].money += Number(s.money) || 0;
  dayMap[dayOfWeek].revenue += Number(s.postbacks_confirmed_money) || 0;
  dayMap[dayOfWeek].count += 1;
});

// Format summary for Claude
let summary = '';
for (const day of dayNames) {
  const d = dayMap[day];
  if (!d) continue;
  const roi = d.money > 0 ? ((d.revenue - d.money) / d.money * 100) : 0;
  const ctr = d.shows > 0 ? (d.clicks / d.shows * 100) : 0;
  const avgSpend = d.count > 0 ? (d.money / d.count) : 0;
  summary += `${day.toUpperCase()}: CTR: ${ctr.toFixed(2)}%, ROI: ${roi.toFixed(0)}%, Clicks: ${d.clicks}, Avg Spend/day: $${avgSpend.toFixed(2)}, Days sampled: ${d.count}\n`;
}

return [{ json: { summary, dayMap } }];

